// Payload: tenant_id, conversation_id, contact_phone, contact_name, messages[], assigned_to_id, department_id, closed_at
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const messages = Array.isArray(body.messages) ? body.messages : [];
const text = messages
  .map(m => `${m.sender_name || m.direction || '?'}: ${(m.content || '').trim()}`)
  .filter(Boolean)
  .join('\n\n');
const model = (body.model && String(body.model).trim()) || 'qwen3:14b';
return [{ json: { prompt: `Resuma esta conversa de atendimento. Extraia em uma frase o assunto principal (subject), sentimento (sentiment: positivo/neutro/negativo), satisfação (satisfaction: 1-5) e um resumo conciso (summary).\n\nMensagens:\n${text || '(vazio)'}`, model } }];

// Resposta do LLM: extrair summary (obrigatório), subject, sentiment, satisfaction
const item = $input.first().json;
const rawText = (item.response || item.message?.content || '').trim() || '(sem resposta)';
// Parse simples: linhas tipo 'summary: ...' ou retorna tudo como summary
let summary = rawText;
let subject = '';
let sentiment = '';
let satisfaction = '';
const lines = rawText.split(/\n/);
for (const line of lines) {
  const m = line.match(/^(summary|subject|sentiment|satisfaction)\s*[:=]\s*(.+)$/i);
  if (m) {
    const key = m[1].toLowerCase();
    const val = m[2].trim();
    if (key === 'summary') summary = val;
    else if (key === 'subject') subject = val;
    else if (key === 'sentiment') sentiment = val;
    else if (key === 'satisfaction') satisfaction = val;
  }
}
return [{ json: { summary: summary || '', subject, sentiment, satisfaction } }];
